import usocket as socket
import ujson as json
import uasyncio as asyncio
from uwebsocket import WS_SERVER

clients = []

async def websocket_handler(ws):
    global clients
    clients.append(ws)
    try:
        while True:
            msg = await ws.recv()
            if msg:
                command = json.loads(msg)
                if 'action' in command:
                    if command['action'] == 'turn_on':
                        # Handle the turn_on action
                        print("Turning on the device")
                    elif command['action'] == 'turn_off':
                        # Handle the turn_off action
                        print("Turning off the device")
    except Exception as e:
        print("Connection error:", e)
    finally:
        clients.remove(ws)
        await ws.close()

async def main():
    server = WS_SERVER(websocket_handler)
    server.start()
    print("WebSocket server running...")
    while True:
        await asyncio.sleep(1)

asyncio.run(main())